import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const phoneRegex = /^\+?\d{8,15}$/;

const normalizePhone = (value = '') => value.replace(/[\s\-()]/g, '');

export default function Register() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    phone: '',
    password: '',
    confirmPassword: '',
  });

  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Update form state and clear the previous error message.
  const handleChange = (e) => {
    setErrorMessage('');
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // Validate customer registration fields before submission.
  const validateForm = () => {
    if (!formData.firstName.trim()) {
      return 'Please enter your first name.';
    }

    if (!formData.lastName.trim()) {
      return 'Please enter your last name.';
    }

    if (!phoneRegex.test(normalizePhone(formData.phone))) {
      return 'Please enter a valid phone number.';
    }

    if (!formData.password || formData.password.length < 6) {
      return 'Password must be at least 6 characters long.';
    }

    if (formData.password !== formData.confirmPassword) {
      return 'Passwords do not match.';
    }

    return '';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const validationMessage = validateForm();
    if (validationMessage) {
      setErrorMessage(validationMessage);
      return;
    }

    try {
      setIsSubmitting(true);
      setErrorMessage('');

      const response = await axiosInstance.post('/api/auth/customer/register', {
        firstName: formData.firstName.trim(),
        lastName: formData.lastName.trim(),
        phone: normalizePhone(formData.phone),
        password: formData.password,
      });

      // Automatically log in the customer after a successful registration.
      login(response.data);

      navigate('/tasks');
    } catch (error) {
      const serverMessage =
        error?.response?.data?.message || 'Registration failed. Please try again.';
      setErrorMessage(serverMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#ececec] flex items-center justify-center px-4">
      <div className="w-[390px] min-h-[844px] bg-[#ececec] px-6 pt-6">
        <div className="flex items-center justify-between text-[14px] font-semibold text-black">
          <span>9:41</span>
          <div className="flex items-center gap-2">
            <div className="w-4 h-2 border border-black rounded-sm" />
            <div className="w-5 h-2 border border-black rounded-sm" />
            <div className="w-6 h-3 border border-black rounded-sm" />
          </div>
        </div>

        <div className="mt-14 flex flex-col items-center">
          <div className="w-[120px] h-[120px] rounded-full bg-white shadow-md flex items-center justify-center">
            <span className="text-[18px] font-bold text-[#4f4f4f]">Register</span>
          </div>

          <h1 className="mt-6 text-[28px] font-bold text-black">Create Account</h1>
          <p className="mt-2 text-[14px] text-gray-600">Parcel Pickup Scheduler</p>
        </div>

        <form onSubmit={handleSubmit} className="mt-8">
          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              First Name
            </label>
            <input
              type="text"
              name="firstName"
              placeholder="Enter your first name"
              value={formData.firstName}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Last Name
            </label>
            <input
              type="text"
              name="lastName"
              placeholder="Enter your last name"
              value={formData.lastName}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Phone Number
            </label>
            <input
              type="text"
              name="phone"
              placeholder="Enter your phone number"
              value={formData.phone}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Password
            </label>
            <input
              type="password"
              name="password"
              placeholder="Enter your password"
              value={formData.password}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Confirm Password
            </label>
            <input
              type="password"
              name="confirmPassword"
              placeholder="Confirm your password"
              value={formData.confirmPassword}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          {errorMessage && (
            <div className="mb-4 rounded-[12px] bg-red-100 px-4 py-3 text-[13px] text-red-700">
              {errorMessage}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full h-[48px] rounded-[12px] bg-[#bfbfbf] text-white text-[18px] font-semibold disabled:opacity-70"
          >
            {isSubmitting ? 'Creating Account...' : 'Register'}
          </button>
        </form>

        <button
          type="button"
          onClick={() => navigate('/customer-login')}
          className="mt-8 w-full text-[15px] text-black underline"
        >
          Already have an account? Log in
        </button>
      </div>
    </div>
  );
}
